module RefModule(LR_in, LR_out, clk, LR_load_en);input             clk;
  input             LR_load_en;		
  input       [7:0] LR_in;	 
  output reg  [7:0] LR_out;			 

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
  begin
    if(LR_load_en)
      LR_out <= LR_in;              

	else
      LR_out <= LR_out;             

  end

endmodule
